// // This module implements a 2-to-1 multiplexer where the output selects between two inputs based on the select signal. When select is 0, the output is inA; when select is 1, the output is inB.
module top_module(select, inA, inB, outC);parameter k = 1;
	input         select;
	input  [k-1:0] inA;
	input  [k-1:0] inB;
	output [k-1:0] outC;

	assign outC = select ? inA : inB;endmodule
